99: void Cluster::startPreInit() {
100:   // If we are attaching to a pre-populated cache we need to initialize our hosts.
101:   std::unique_ptr<Upstream::HostVector> hosts_added;
102:   dns_cache_->iterateHostMap(
103:       [&](absl::string_view host, const Common::DynamicForwardProxy::DnsHostInfoSharedPtr& info) {
104:         addOrUpdateHost(host, info, hosts_added);
105:       });
106:   if (hosts_added) {
107:     updatePriorityState(*hosts_added, {});
108:   }
109:   onPreInitComplete();
110: }
