112: bool Cluster::touch(const std::string& cluster_name) {
113:   absl::ReaderMutexLock lock{&cluster_map_lock_};
114:   const auto cluster_it = cluster_map_.find(cluster_name);
115:   if (cluster_it != cluster_map_.end()) {
116:     cluster_it->second->touch();
117:     return true;
118:   }
119:   ENVOY_LOG(debug, "cluster='{}' has been removed while touching", cluster_name);
120:   return false;
121: }
