445: void Cluster::LoadBalancer::onConnectionOpen(Envoy::Http::ConnectionPool::Instance& pool,
446:                                              std::vector<uint8_t>& hash_key,
447:                                              const Network::Connection& connection) {
448:   // Only coalesce connections that are over TLS.
449:   if (!connection.ssl()) {
450:     return;
451:   }
452:   const std::string alpn = connection.nextProtocol();
453:   if (alpn != Http::Utility::AlpnNames::get().Http2 &&
454:       alpn != Http::Utility::AlpnNames::get().Http3) {
455:     // Only coalesce connections for HTTP/2 and HTTP/3.
456:     return;
457:   }
458:   const LookupKey key = {hash_key, *connection.connectionInfoProvider().remoteAddress()};
459:   ConnectionInfo info = {&pool, &connection};
460:   connection_info_map_[key].push_back(info);
461: }
462: 
463: void Cluster::LoadBalancer::onConnectionDraining(Envoy::Http::ConnectionPool::Instance& pool,
464:                                                  std::vector<uint8_t>& hash_key,
465:                                                  const Network::Connection& connection) {
466:   const LookupKey key = {hash_key, *connection.connectionInfoProvider().remoteAddress()};
467:   connection_info_map_[key].erase(
468:       std::remove_if(connection_info_map_[key].begin(), connection_info_map_[key].end(),
469:                      [&pool, &connection](const ConnectionInfo& info) {
470:                        return (info.pool_ == &pool && info.connection_ == &connection);
471:                      }),
472:       connection_info_map_[key].end());
473: }
