289:   update_callbacks_->onDnsHostAddOrUpdate("host2:0", host_map_["host2:0"]);
290:   EXPECT_CALL(*host_map_["host2:0"], touch());
291:   EXPECT_EQ("5.6.7.8:0",
292:             lb_->chooseHost(setHostAndReturnContext("host2:0"))->address()->asString());
293: 
294:   // Fail outlier check for host1
295:   setOutlierFailed("host1:0");
296:   EXPECT_EQ(nullptr, lb_->chooseHost(setHostAndReturnContext("host1:0")));
297:   // "host2:0" should not be affected
298:   EXPECT_CALL(*host_map_["host2:0"], touch());
299:   EXPECT_EQ("5.6.7.8:0",
300:             lb_->chooseHost(setHostAndReturnContext("host2:0"))->address()->asString());
301: 
302:   // Clear outlier check failure for host1, it should be available again
303:   clearOutlierFailed("host1:0");
304:   EXPECT_CALL(*host_map_["host1:0"], touch());
305:   EXPECT_EQ("1.2.3.4:0",
306:             lb_->chooseHost(setHostAndReturnContext("host1:0"))->address()->asString());
307: }
