84: createProtocolOptionsConfig(const std::string& name, const ProtobufWkt::Any& typed_config,
85:                             Server::Configuration::ProtocolOptionsFactoryContext& factory_context) {
86:   Server::Configuration::ProtocolOptionsFactory* factory =
87:       Registry::FactoryRegistry<Server::Configuration::NamedNetworkFilterConfigFactory>::getFactory(
88:           name);
89:   if (factory == nullptr) {
90:     factory =
91:         Registry::FactoryRegistry<Server::Configuration::NamedHttpFilterConfigFactory>::getFactory(
92:             name);
93:   }
94:   if (factory == nullptr) {
95:     factory =
96:         Registry::FactoryRegistry<Server::Configuration::ProtocolOptionsFactory>::getFactory(name);
97:   }
98: 
99:   if (factory == nullptr) {
100:     throwEnvoyExceptionOrPanic(
101:         fmt::format("Didn't find a registered network or http filter or protocol "
102:                     "options implementation for name: '{}'",
103:                     name));
104:   }
105: 
106:   ProtobufTypes::MessagePtr proto_config = factory->createEmptyProtocolOptionsProto();
107: 
108:   if (proto_config == nullptr) {
109:     throwEnvoyExceptionOrPanic(fmt::format("filter {} does not support protocol options", name));
110:   }
111: 
112:   Envoy::Config::Utility::translateOpaqueConfig(
113:       typed_config, factory_context.messageValidationVisitor(), *proto_config);
114:   return factory->createProtocolOptionsConfig(*proto_config, factory_context);
