133: // Updates the EDS health flags for an existing host to match the new host.
134: // @param updated_host the new host to read health flag values from.
135: // @param existing_host the host to update.
136: // @return bool whether the flag update caused the host health to change.
137: bool updateEdsHealthFlag(const Host& updated_host, Host& existing_host) {
138:   auto updated_eds_health_status = updated_host.edsHealthStatus();
139: 
140:   // Check if the health flag has changed.
141:   if (updated_eds_health_status == existing_host.edsHealthStatus()) {
142:     return false;
143:   }
144: 
145:   const auto previous_health = existing_host.coarseHealth();
146:   existing_host.setEdsHealthStatus(updated_eds_health_status);
147: 
148:   // Rebuild if changing the flag affected the host health.
149:   return previous_health != existing_host.coarseHealth();
150: }
