175: Network::ConnectionSocket::OptionsSharedPtr
176: buildBaseSocketOptions(const envoy::config::cluster::v3::Cluster& cluster_config,
177:                        const envoy::config::core::v3::BindConfig& bootstrap_bind_config) {
178:   Network::ConnectionSocket::OptionsSharedPtr base_options =
179:       std::make_shared<Network::ConnectionSocket::Options>();
180: 
181:   // The process-wide `signal()` handling may fail to handle SIGPIPE if overridden
182:   // in the process (i.e., on a mobile client). Some OSes support handling it at the socket layer:
183:   if (ENVOY_SOCKET_SO_NOSIGPIPE.hasValue()) {
184:     Network::Socket::appendOptions(base_options,
185:                                    Network::SocketOptionFactory::buildSocketNoSigpipeOptions());
186:   }
187:   // Cluster IP_FREEBIND settings, when set, will override the cluster manager wide settings.
188:   if ((bootstrap_bind_config.freebind().value() &&
189:        !cluster_config.upstream_bind_config().has_freebind()) ||
190:       cluster_config.upstream_bind_config().freebind().value()) {
191:     Network::Socket::appendOptions(base_options,
192:                                    Network::SocketOptionFactory::buildIpFreebindOptions());
193:   }
194:   if (cluster_config.upstream_connection_options().has_tcp_keepalive()) {
195:     Network::Socket::appendOptions(base_options,
196:                                    Network::SocketOptionFactory::buildTcpKeepaliveOptions(
197:                                        parseTcpKeepaliveConfig(cluster_config)));
198:   }
199: 
200:   return base_options;
201: }
