221: std::vector<::Envoy::Upstream::UpstreamLocalAddress>
222: parseBindConfig(::Envoy::OptRef<const envoy::config::core::v3::BindConfig> bind_config,
223:                 const absl::optional<std::string>& cluster_name,
224:                 Network::ConnectionSocket::OptionsSharedPtr base_socket_options,
225:                 Network::ConnectionSocket::OptionsSharedPtr cluster_socket_options) {
226: 
227:   std::vector<::Envoy::Upstream::UpstreamLocalAddress> upstream_local_addresses;
228:   if (bind_config.has_value()) {
229:     UpstreamLocalAddress upstream_local_address;
230:     upstream_local_address.address_ = nullptr;
231:     if (bind_config->has_source_address()) {
232: 
233:       auto address_or_error =
234:           ::Envoy::Network::Address::resolveProtoSocketAddress(bind_config->source_address());
235:       THROW_IF_STATUS_NOT_OK(address_or_error, throw);
236:       upstream_local_address.address_ = address_or_error.value();
237:     }
238:     upstream_local_address.socket_options_ = std::make_shared<Network::ConnectionSocket::Options>();
239: 
240:     ::Envoy::Network::Socket::appendOptions(upstream_local_address.socket_options_,
241:                                             base_socket_options);
242:     ::Envoy::Network::Socket::appendOptions(upstream_local_address.socket_options_,
243:                                             cluster_socket_options);
244: 
245:     upstream_local_addresses.push_back(upstream_local_address);
246: 
247:     for (const auto& extra_source_address : bind_config->extra_source_addresses()) {
248:       UpstreamLocalAddress extra_upstream_local_address;
249:       auto address_or_error =
250:           ::Envoy::Network::Address::resolveProtoSocketAddress(extra_source_address.address());
251:       THROW_IF_STATUS_NOT_OK(address_or_error, throw);
252:       extra_upstream_local_address.address_ = address_or_error.value();
253: 
254:       extra_upstream_local_address.socket_options_ =
255:           std::make_shared<::Envoy::Network::ConnectionSocket::Options>();
256:       ::Envoy::Network::Socket::appendOptions(extra_upstream_local_address.socket_options_,
257:                                               base_socket_options);
258: 
259:       if (extra_source_address.has_socket_options()) {
260:         ::Envoy::Network::Socket::appendOptions(
261:             extra_upstream_local_address.socket_options_,
262:             ::Envoy::Network::SocketOptionFactory::buildLiteralOptions(
263:                 extra_source_address.socket_options().socket_options()));
264:       } else {
265:         ::Envoy::Network::Socket::appendOptions(extra_upstream_local_address.socket_options_,
266:                                                 cluster_socket_options);
267:       }
268:       upstream_local_addresses.push_back(extra_upstream_local_address);
269:     }
270: 
271:     for (const auto& additional_source_address : bind_config->additional_source_addresses()) {
272:       UpstreamLocalAddress additional_upstream_local_address;
273:       auto address_or_error =
274:           ::Envoy::Network::Address::resolveProtoSocketAddress(additional_source_address);
275:       THROW_IF_STATUS_NOT_OK(address_or_error, throw);
276:       additional_upstream_local_address.address_ = address_or_error.value();
277:       additional_upstream_local_address.socket_options_ =
278:           std::make_shared<::Envoy::Network::ConnectionSocket::Options>();
279:       ::Envoy::Network::Socket::appendOptions(additional_upstream_local_address.socket_options_,
280:                                               base_socket_options);
281:       ::Envoy::Network::Socket::appendOptions(additional_upstream_local_address.socket_options_,
282:                                               cluster_socket_options);
283:       upstream_local_addresses.push_back(additional_upstream_local_address);
284:     }
285:   } else {
286:     // If there is no bind config specified, then return a nullptr for the address.
287:     UpstreamLocalAddress local_address;
288:     local_address.address_ = nullptr;
289:     local_address.socket_options_ = std::make_shared<::Envoy::Network::ConnectionSocket::Options>();
290:     ::Envoy::Network::Socket::appendOptions(local_address.socket_options_, base_socket_options);
291:     Network::Socket::appendOptions(local_address.socket_options_, cluster_socket_options);
292:     upstream_local_addresses.push_back(local_address);
293:   }
294: 
295:   // Verify that we have valid addresses if size is greater than 1.
296:   if (upstream_local_addresses.size() > 1) {
297:     for (auto const& upstream_local_address : upstream_local_addresses) {
298:       if (upstream_local_address.address_ == nullptr) {
299:         throwEnvoyExceptionOrPanic(fmt::format(
300:             "{}'s upstream binding config has invalid IP addresses.",
301:             !(cluster_name.has_value()) ? "Bootstrap"
302:                                         : fmt::format("Cluster {}", cluster_name.value())));
303:       }
304:     }
305:   }
306: 
307:   return upstream_local_addresses;
308: }
