310: Envoy::Upstream::UpstreamLocalAddressSelectorConstSharedPtr createUpstreamLocalAddressSelector(
311:     const envoy::config::cluster::v3::Cluster& cluster_config,
312:     const absl::optional<envoy::config::core::v3::BindConfig>& bootstrap_bind_config) {
313: 
314:   // Use the cluster bind config if specified. This completely overrides the
315:   // bootstrap bind config when present.
316:   OptRef<const envoy::config::core::v3::BindConfig> bind_config;
317:   absl::optional<std::string> cluster_name;
318:   if (cluster_config.has_upstream_bind_config()) {
319:     bind_config.emplace(cluster_config.upstream_bind_config());
320:     cluster_name.emplace(cluster_config.name());
321:   } else if (bootstrap_bind_config.has_value()) {
322:     bind_config.emplace(*bootstrap_bind_config);
323:   }
324: 
325:   // Verify that bind config is valid.
326:   if (bind_config.has_value()) {
327:     if (bind_config->additional_source_addresses_size() > 0 &&
328:         bind_config->extra_source_addresses_size() > 0) {
329:       throwEnvoyExceptionOrPanic(fmt::format(
330:           "Can't specify both `extra_source_addresses` and `additional_source_addresses` "
331:           "in the {}'s upstream binding config",
332:           !(cluster_name.has_value()) ? "Bootstrap"
333:                                       : fmt::format("Cluster {}", cluster_name.value())));
334:     }
335: 
336:     if (!bind_config->has_source_address() &&
337:         (bind_config->extra_source_addresses_size() > 0 ||
338:          bind_config->additional_source_addresses_size() > 0)) {
339:       throwEnvoyExceptionOrPanic(fmt::format(
340:           "{}'s upstream binding config has extra/additional source addresses but no "
341:           "source_address. Extra/additional addresses cannot be specified if "
342:           "source_address is not set.",
343:           !(cluster_name.has_value()) ? "Bootstrap"
344:                                       : fmt::format("Cluster {}", cluster_name.value())));
345:     }
346:   }
347:   UpstreamLocalAddressSelectorFactory* local_address_selector_factory;
348:   const envoy::config::core::v3::TypedExtensionConfig* const local_address_selector_config =
349:       bind_config.has_value() && bind_config->has_local_address_selector()
350:           ? &bind_config->local_address_selector()
351:           : nullptr;
352:   if (local_address_selector_config) {
353:     local_address_selector_factory =
354:         Config::Utility::getAndCheckFactory<UpstreamLocalAddressSelectorFactory>(
355:             *local_address_selector_config, false);
356:   } else {
357:     // Create the default local address selector if one was not specified.
358:     envoy::config::upstream::local_address_selector::v3::DefaultLocalAddressSelector default_config;
359:     envoy::config::core::v3::TypedExtensionConfig typed_extension;
360:     typed_extension.mutable_typed_config()->PackFrom(default_config);
361:     local_address_selector_factory =
362:         Config::Utility::getAndCheckFactory<UpstreamLocalAddressSelectorFactory>(typed_extension,
363:                                                                                  false);
364:   }
365:   auto selector_or_error = local_address_selector_factory->createLocalAddressSelector(
366:       parseBindConfig(
367:           bind_config, cluster_name,
368:           buildBaseSocketOptions(cluster_config, bootstrap_bind_config.value_or(
369:                                                      envoy::config::core::v3::BindConfig{})),
370:           buildClusterSocketOptions(cluster_config, bootstrap_bind_config.value_or(
371:                                                         envoy::config::core::v3::BindConfig{}))),
372:       cluster_name);
373:   THROW_IF_STATUS_NOT_OK(selector_or_error, throw);
374:   return selector_or_error.value();
375: }
