  EXPECT_CALL(host, address()).WillRepeatedly(testing::Return(address));
  std::vector<uint8_t> hash_key = {1, 2, 3};

  Envoy::Http::ConnectionPool::MockInstance pool;
  Envoy::Network::MockConnection connection;
