   325→Cluster::LoadBalancer::chooseHost(Upstream::LoadBalancerContext* context) {
   326→  if (!context) {
   327→    return nullptr;
   328→  }
   329→
   330→  const Router::StringAccessor* dynamic_host_filter_state = nullptr;
   331→  if (context->requestStreamInfo()) {
   332→    dynamic_host_filter_state =
   333→        context->requestStreamInfo()->filterState().getDataReadOnly<Router::StringAccessor>(
   334→            DynamicHostFilterStateKey);
   335→  }
   336→
   337→  absl::string_view raw_host;
   338→  if (dynamic_host_filter_state) {
   339→    raw_host = dynamic_host_filter_state->asString();
   340→  } else if (context->downstreamHeaders()) {
   341→    raw_host = context->downstreamHeaders()->getHostValue();
   342→  } else if (context->downstreamConnection()) {
   343→    raw_host = context->downstreamConnection()->requestedServerName();
   344→  }
   345→
   346→  // For host lookup, we need to make sure to match the host of any DNS cache
   347→  // insert. Two code points currently do DNS cache insert: the http DFP filter,
   348→  // which inserts for HTTP traffic, and sets port based on the cluster's
   349→  // security level, and the SNI DFP network filter which sets port based on
   350→  // stream metadata, or configuration (which is then added as stream metadata).
   351→  const bool is_secure = cluster_.info()
   352→                             ->transportSocketMatcher()
   353→                             .resolve(nullptr)
   354→                             .factory_.implementsSecureTransport();
   355→  uint32_t port = is_secure ? 443 : 80;
   356→  if (context->requestStreamInfo()) {
   357→    const StreamInfo::UInt32Accessor* dynamic_port_filter_state =
   358→        context->requestStreamInfo()->filterState().getDataReadOnly<StreamInfo::UInt32Accessor>(
   359→            DynamicPortFilterStateKey);
   360→    if (dynamic_port_filter_state != nullptr && dynamic_port_filter_state->value() > 0 &&
   361→        dynamic_port_filter_state->value() <= 65535) {
   362→      port = dynamic_port_filter_state->value();
   363→    }
   364→  }
   365→
   366→  std::string host = Common::DynamicForwardProxy::DnsHostInfo::normalizeHostForDfp(raw_host, port);
   367→
   368→  if (host.empty()) {
   369→    ENVOY_LOG(debug, "host empty");
   370→    return nullptr;
   371→  }
   372→
   373→  if (cluster_.enableSubCluster()) {
   374→    return cluster_.chooseHost(host, context);
   375→  }
   376→
   377→  {
   378→    absl::ReaderMutexLock lock{&cluster_.host_map_lock_};
   379→    const auto host_it = cluster_.host_map_.find(host);
   380→    if (host_it == cluster_.host_map_.end()) {
   381→      ENVOY_LOG(debug, "host {} not found", host);
   382→      return nullptr;
   383→    } else {
   384→      if (host_it->second.logical_host_->coarseHealth() == Upstream::Host::Health::Unhealthy) {
   385→        ENVOY_LOG(debug, "host {} is unhealthy", host);
   386→        return nullptr;
   387→      }
   388→      host_it->second.shared_host_info_->touch();
   389→      return host_it->second.logical_host_;
   390→    }
   391→  }
