   430→void Cluster::LoadBalancer::onConnectionOpen(Envoy::Http::ConnectionPool::Instance& pool,
   431→                                             std::vector<uint8_t>& hash_key,
   432→                                             const Network::Connection& connection) {
   433→  // Only coalesce connections that are over TLS.
   434→  if (!connection.ssl()) {
   435→    return;
   436→  }
   437→  const std::string alpn = connection.nextProtocol();
   438→  if (alpn != Http::Utility::AlpnNames::get().Http2 &&
   439→      alpn != Http::Utility::AlpnNames::get().Http3) {
   440→    // Only coalesce connections for HTTP/2 and HTTP/3.
   441→    return;
   442→  }
   443→  const LookupKey key = {hash_key, *connection.connectionInfoProvider().remoteAddress()};
   444→  ConnectionInfo info = {&pool, &connection};
   445→  connection_info_map_[key].push_back(info);
   446→}
