   448→void Cluster::LoadBalancer::onConnectionDraining(Envoy::Http::ConnectionPool::Instance& pool,
   449→                                                 std::vector<uint8_t>& hash_key,
   450→                                                 const Network::Connection& connection) {
   451→  const LookupKey key = {hash_key, *connection.connectionInfoProvider().remoteAddress()};
   452→  connection_info_map_[key].erase(
   453→      std::remove_if(connection_info_map_[key].begin(), connection_info_map_[key].end(),
   454→                     [&pool, &connection](const ConnectionInfo& info) {
   455→                       return (info.pool_ == &pool && info.connection_ == &connection);
   456→                     }),
   457→      connection_info_map_[key].end());
