void Cluster::addOrUpdateHost(
    absl::string_view host,
    const Extensions::Common::DynamicForwardProxy::DnsHostInfoSharedPtr& host_info) {
  Upstream::HostVector hosts_added;
  Upstream::HostVector hosts_removed;
  Upstream::LogicalHostSharedPtr emplaced_host;
  {
    absl::WriterMutexLock lock{&host_map_lock_};

    // NOTE: Right now we allow a DNS cache to be shared between multiple clusters. Though we have
    // connection/request circuit breakers on the cluster, we don't have any way to control the
    // maximum hosts on a cluster. We currently assume that host data shared via shared pointer is
    // a marginal memory cost above that already used by connections and requests, so relying on
    // connection/request circuit breakers is sufficient. We may have to revisit this in the
    // future.
    const auto host_map_it = host_map_.find(host);
    if (host_map_it != host_map_.end()) {
      // Host exists with a different address, so we need to remove the old one and create a new
      // one to properly update the cross-priority host map.
      ASSERT(host_info == host_map_it->second.shared_host_info_);
      ASSERT(host_info->address() != host_map_it->second.logical_host_->address());
      ENVOY_LOG(debug, "updating dfproxy cluster host address '{}' from '{}' to '{}'", host,
                host_map_it->second.logical_host_->address()->asString(),
                host_info->address()->asString());

      // Remove the old host.
      hosts_removed.emplace_back(host_map_it->second.logical_host_);
      host_map_.erase(host_map_it);

      // Create and add the new host with the updated address.
      emplaced_host = std::make_shared<Upstream::LogicalHost>(
          info(), std::string{host}, host_info->address(), host_info->addressList(),
          dummy_locality_lb_endpoint_, dummy_lb_endpoint_, nullptr, time_source_);
      host_map_.try_emplace(host, host_info, emplaced_host);
      hosts_added.emplace_back(emplaced_host);
    }
  }

  // Call updatePriorityState with both hosts_removed and hosts_added (for update case)
  // or just hosts_added (for new host case).
  updatePriorityState(hosts_added, hosts_removed);
  return;
}

